local base_dir = "./files/"

local function is_safe_path(requested_path)
    local real_base = ngx.var.document_root .. base_dir
    local real_requested = ngx.re.sub(requested_path, [[^/]], "", "jo")
    local full_path = real_base .. real_requested

    return full_path:sub(1, #real_base) == real_base and not full_path:find("%.%./") and not full_path:find("/%./")
end

local filename = ngx.var.arg_filename

if not filename or not is_safe_path(filename) then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Invalid filename.")
    return
end

local file_path = base_dir .. filename
local file, err = io.open(file_path, "r")

if not file then
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say("File not found: " .. err)
    return
end

local content = file:read("*a")
file:close()

ngx.header.content_type = "application/octet-stream"
ngx.say(content)